const express = require('express');
const jwt = require('jsonwebtoken');
const jwksClient = require('jwks-rsa');

const app = express();
const port = 3000;

// Replace with your JWKS Uri
const jwksUri = 'https://your-auth-domain/.well-known/jwks.json';

// JWKS client to fetch and cache the signing keys
const client = jwksClient({
  jwksUri,
  cache: true,
  rateLimit: true,
  jwksRequestsPerMinute: 10,
});

const getKey = (header, callback) => {
  if (!header.kid) {
    return callback(new Error('Missing kid in token header'));
  }

  client.getSigningKey(header.kid, (err, key) => {
    if (err) {
      return callback(err);
    }
    const signingKey = key.getPublicKey();
    callback(null, signingKey);
  });
};

const verifyToken = (token, callback) => {
  jwt.verify(
    token,
    getKey,
    {
      audience: 'your-audience',
      issuer: 'https://your-auth-domain/',
      algorithms: ['RS256'],
    },
    callback
  );
};

app.use((req, res, next) => {
  const authHeader = req.headers.authorization;

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Unauthorized' });
  }

  const token = authHeader.split(' ')[1];

  verifyToken(token, (err, decoded) => {
    if (err) {
      return res.status(401).json({ error: 'Unauthorized', details: err.message });
    }
    req.user = decoded;
    next();
  });
});

app.get('/protected', (req, res) => {
  res.json({ message: 'This is a protected resource', user: req.user });
});

app.listen(port, () => {
  console.log(`Resource server listening on port ${port}`);
});